-- =============================================================
-- Test database setup for tabularis-db2-plugin integration tests
-- Run with: db2 -tvf setup.sql
-- =============================================================

-- Schema
CREATE SCHEMA TEST_SCHEMA;

-- ---------------------------------------------------------
-- Core tables
-- ---------------------------------------------------------

CREATE TABLE TEST_SCHEMA.DEPARTMENTS (
    DEPT_ID INTEGER NOT NULL GENERATED ALWAYS AS IDENTITY (START WITH 1 INCREMENT BY 1),
    DEPT_NAME VARCHAR(100) NOT NULL,
    LOCATION VARCHAR(200),
    BUDGET DECIMAL(15, 2),
    CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (DEPT_ID)
);

CREATE TABLE TEST_SCHEMA.EMPLOYEES (
    EMP_ID INTEGER NOT NULL GENERATED ALWAYS AS IDENTITY (START WITH 1 INCREMENT BY 1),
    FIRST_NAME VARCHAR(50) NOT NULL,
    LAST_NAME VARCHAR(50) NOT NULL,
    EMAIL VARCHAR(100) NOT NULL,
    HIRE_DATE DATE NOT NULL,
    SALARY DECIMAL(10, 2),
    IS_ACTIVE SMALLINT DEFAULT 1,
    DEPT_ID INTEGER,
    NOTES CLOB,
    PRIMARY KEY (EMP_ID),
    CONSTRAINT FK_EMP_DEPT FOREIGN KEY (DEPT_ID)
        REFERENCES TEST_SCHEMA.DEPARTMENTS (DEPT_ID) ON DELETE SET NULL
);

CREATE TABLE TEST_SCHEMA.PROJECTS (
    PROJECT_ID INTEGER NOT NULL GENERATED ALWAYS AS IDENTITY (START WITH 1 INCREMENT BY 1),
    PROJECT_NAME VARCHAR(200) NOT NULL,
    START_DATE DATE,
    END_DATE DATE,
    STATUS VARCHAR(20) DEFAULT 'ACTIVE',
    DEPT_ID INTEGER NOT NULL,
    PRIMARY KEY (PROJECT_ID),
    CONSTRAINT FK_PROJ_DEPT FOREIGN KEY (DEPT_ID)
        REFERENCES TEST_SCHEMA.DEPARTMENTS (DEPT_ID) ON DELETE CASCADE
);

CREATE TABLE TEST_SCHEMA.EMP_PROJECTS (
    EMP_ID INTEGER NOT NULL,
    PROJECT_ID INTEGER NOT NULL,
    ROLE VARCHAR(50) DEFAULT 'MEMBER',
    ASSIGNED_DATE DATE DEFAULT CURRENT_DATE,
    PRIMARY KEY (EMP_ID, PROJECT_ID),
    CONSTRAINT FK_EP_EMP FOREIGN KEY (EMP_ID)
        REFERENCES TEST_SCHEMA.EMPLOYEES (EMP_ID) ON DELETE CASCADE,
    CONSTRAINT FK_EP_PROJ FOREIGN KEY (PROJECT_ID)
        REFERENCES TEST_SCHEMA.PROJECTS (PROJECT_ID) ON DELETE CASCADE
);

-- ---------------------------------------------------------
-- Data type coverage table
-- ---------------------------------------------------------

CREATE TABLE TEST_SCHEMA.DATA_TYPES_TEST (
    ID INTEGER NOT NULL GENERATED ALWAYS AS IDENTITY,
    COL_SMALLINT SMALLINT,
    COL_INTEGER INTEGER,
    COL_BIGINT BIGINT,
    COL_DECIMAL DECIMAL(18, 4),
    COL_REAL REAL,
    COL_DOUBLE DOUBLE,
    COL_CHAR CHAR(10),
    COL_VARCHAR VARCHAR(255),
    COL_CLOB CLOB(1M),
    COL_DATE DATE,
    COL_TIME TIME,
    COL_TIMESTAMP TIMESTAMP,
    COL_BLOB BLOB(1M),
    PRIMARY KEY (ID)
);

-- ---------------------------------------------------------
-- CRUD test table (non-identity PK for explicit inserts)
-- ---------------------------------------------------------

CREATE TABLE TEST_SCHEMA.CRUD_TEST (
    ID INTEGER NOT NULL,
    NAME VARCHAR(100),
    VALUE DECIMAL(10, 2),
    PRIMARY KEY (ID)
);

-- ---------------------------------------------------------
-- Drop-operation test tables
-- ---------------------------------------------------------

CREATE TABLE TEST_SCHEMA.DROP_TEST_PARENT (
    ID INTEGER NOT NULL,
    PRIMARY KEY (ID)
);

INSERT INTO TEST_SCHEMA.DROP_TEST_PARENT (ID) VALUES (1);
INSERT INTO TEST_SCHEMA.DROP_TEST_PARENT (ID) VALUES (2);
INSERT INTO TEST_SCHEMA.DROP_TEST_PARENT (ID) VALUES (3);

CREATE TABLE TEST_SCHEMA.DROP_TEST (
    ID INTEGER NOT NULL,
    PARENT_ID INTEGER,
    NAME VARCHAR(100),
    PRIMARY KEY (ID),
    CONSTRAINT FK_DROP_TEST FOREIGN KEY (PARENT_ID)
        REFERENCES TEST_SCHEMA.DROP_TEST_PARENT (ID)
);

CREATE INDEX TEST_SCHEMA.IDX_DROP_TEST_NAME ON TEST_SCHEMA.DROP_TEST (NAME);

-- ---------------------------------------------------------
-- Indexes
-- ---------------------------------------------------------

CREATE INDEX TEST_SCHEMA.IDX_EMP_LAST_NAME ON TEST_SCHEMA.EMPLOYEES (LAST_NAME);
CREATE UNIQUE INDEX TEST_SCHEMA.IDX_EMP_EMAIL ON TEST_SCHEMA.EMPLOYEES (EMAIL);
CREATE INDEX TEST_SCHEMA.IDX_PROJ_STATUS ON TEST_SCHEMA.PROJECTS (STATUS, START_DATE);

-- ---------------------------------------------------------
-- Views
-- ---------------------------------------------------------

CREATE VIEW TEST_SCHEMA.V_EMP_DETAILS AS
    SELECT
        e.EMP_ID,
        e.FIRST_NAME,
        e.LAST_NAME,
        e.EMAIL,
        e.HIRE_DATE,
        e.SALARY,
        d.DEPT_NAME,
        d.LOCATION
    FROM TEST_SCHEMA.EMPLOYEES e
    LEFT JOIN TEST_SCHEMA.DEPARTMENTS d ON e.DEPT_ID = d.DEPT_ID;

CREATE VIEW TEST_SCHEMA.V_DEPT_SUMMARY AS
    SELECT
        d.DEPT_ID,
        d.DEPT_NAME,
        COUNT(e.EMP_ID) AS EMP_COUNT,
        COALESCE(AVG(e.SALARY), 0) AS AVG_SALARY
    FROM TEST_SCHEMA.DEPARTMENTS d
    LEFT JOIN TEST_SCHEMA.EMPLOYEES e ON d.DEPT_ID = e.DEPT_ID
    GROUP BY d.DEPT_ID, d.DEPT_NAME;

